jQuery(window).on("elementor/frontend/init",function(){elementorFrontend.hooks.addAction("frontend/element_ready/premium-addon-icon-box.default",function(e,n){if(e.find(".elementor-invisible").removeClass("elementor-invisible"),e.find(".premium-icon-box-container-in").data("box-tilt")){var o=e.data("box-tilt-reverse");UniversalTilt.init({elements:e,settings:{reverse:o},callbacks:{onMouseLeave:function(e){e.style.boxShadow="0 45px 100px rgba(255, 255, 255, 0)"},onDeviceMove:function(e){e.style.boxShadow="0 45px 100px rgba(255, 255, 255, 0.3)"}}})}})});